package org.dashbuilder.dataset;

import java.util.List;
import java.util.ArrayList;

/**
 * A set of constraints over the structure of a DataSet instance.
 */
public class DataSetConstraints<T> {

    public static final int ERROR_COLUMN_TYPE = 100;
    public static final int ERROR_COLUMN_NUMBER = 101;

    protected List<ColumnType[]> columnTypeList = new ArrayList<ColumnType[]>();
    protected int minColumns = -1;
    protected int maxColumns = -1;
    protected boolean extraColumnsAllowed = false;
    protected ColumnType extraColumnsType = null;

    public ColumnType[] getColumnTypes() {
        if (columnTypeList.isEmpty()) return null;
        return columnTypeList.get(0);
    }

    public ColumnType[] getColumnTypes(int numberOfColumns) {
        if (columnTypeList.isEmpty()) return null;
        for (ColumnType[] types : columnTypeList) {
            if (types.length == numberOfColumns) return types;
        }
        return columnTypeList.get(0);
    }

    public T setColumnTypes(ColumnType[]... typeList) {
        columnTypeList.clear();
        if (typeList != null) {
            for (ColumnType[] types : typeList) {
                _checkSizes(minColumns, maxColumns, types);
                this.columnTypeList.add(types);
            }
        }
        return (T) this;
    }

    public int getMaxColumns() {
        return maxColumns;
    }

    public T setMaxColumns(int maxColumns) {
        for (ColumnType[] types : columnTypeList) {
            _checkSizes(minColumns, maxColumns, types);
        }
        this.maxColumns = maxColumns;
        return (T) this;
    }

    public int getMinColumns() {
        return minColumns;
    }

    public T setMinColumns(int minColumns) {
        for (ColumnType[] types : columnTypeList) {
            _checkSizes(minColumns, maxColumns, types);
        }
        this.minColumns = minColumns;
        return (T) this;
    }

    public boolean areExtraColumnsAllowed() {
        return extraColumnsAllowed;
    }

    public T setExtraColumnsAllowed(boolean extraColumnsAllowed) {
        this.extraColumnsAllowed = extraColumnsAllowed;
        return (T) this;
    }

    public ColumnType getExtraColumnsType() {
        return extraColumnsType;
    }

    public T setExtraColumnsType(ColumnType extraColumnsType) {
        this.extraColumnsType = extraColumnsType;
        return (T) this;
    }

    private void _checkSizes(int min, int max, ColumnType[] types) {
        if (min == 0) {
            throw new IllegalArgumentException("Minimum data set columns must be greater than or equal to 1. Actual=" + min);
        }
        if (max == 0) {
            throw new IllegalArgumentException("Maximum data set columns must be greater than or equal to 1. Actual=" + max);
        }
        if (min != -1 && max != -1 && min > max) {
            throw new IllegalArgumentException("Min=" + min + " data set columns cannot be greater than the max=" + max);
        }
        if (types != null) {
            if (min != -1 && types.length < min) {
                throw new IllegalArgumentException("columnTypes is smaller than " + min);
            }
            if (max != -1 && types.length > max) {
                throw new IllegalArgumentException("columnTypes is greater than " + max);
            }
        }
    }

    public ValidationError check(DataSet dataSet) {

        if (minColumns != -1 && dataSet.getColumns().size() < minColumns) {
            return createValidationError(ERROR_COLUMN_NUMBER);
        }
        if (maxColumns != -1 && dataSet.getColumns().size() > maxColumns) {
            return createValidationError(ERROR_COLUMN_NUMBER);
        }
        ValidationError error = null;
        boolean ok = false;
        int currentColumns  = -1;
        for (ColumnType[] types : columnTypeList) {
            if (currentColumns < 0 || currentColumns < types.length) currentColumns = types.length;
            error = checkTypes(dataSet, types);
            if (!ok && error == null) ok = true;
        }
        if (!ok) return error;

        // Check extra columns type
        if (currentColumns > 0 && extraColumnsAllowed && extraColumnsType != null && dataSet.getColumns().size() > currentColumns) {
            for (int i = currentColumns; i < dataSet.getColumns().size(); i++) {
                ColumnType columnType = dataSet.getColumnByIndex(i).getColumnType();
                if (!columnType.equals(extraColumnsType)) {
                    return createValidationError(ERROR_COLUMN_TYPE, i, extraColumnsType, columnType);
                }
            }
        }
        return null;
    }

    private ValidationError checkTypes(DataSet dataSet, ColumnType[] types) {
        for (int i = 0; i < dataSet.getColumns().size(); i++) {
            ColumnType columnType = dataSet.getColumnByIndex(i).getColumnType();
            if (i < types.length && !columnType.equals(types[i])) {
                return createValidationError(ERROR_COLUMN_TYPE, i, types[i], columnType);
            }
        }
        return null;
    }

    protected ValidationError createValidationError(int error, Object... params) {
        switch (error) {
            case ERROR_COLUMN_NUMBER:
                return new ValidationError(error, "Number of columns exceeds the limits ["
                        + (minColumns == -1 ? 0 : minColumns) + ", " + (maxColumns != -1 ? maxColumns : "unlimited") + "]");
            case ERROR_COLUMN_TYPE:
                Integer idx = (Integer) params[0];
                ColumnType expected = (ColumnType) params[1];
                ColumnType found = (ColumnType) params[2];
                return new ValidationError(error, "Column " + idx + " type=" + found + ", expected=" + expected);
        }
        return new ValidationError(error);
    }
}

require('dotenv').config();

const { TruffleProvider } = require('@harmony-js/core');

const operator_private_key = process.env.OPERATOR_PRIVATE_KEY;
const operator_meemonic = process.env.OPERATOR_MNEMONIC;
const testnet_url = process.env.TESTNET_0_URL;
//Mainnet
const mainnet_mnemonic = process.env.MAINNET_MNEMONIC;
const mainnet_private_key = process.env.MAINNET_PRIVATE_KEY;
const mainnet_url = process.env.MAINNET_0_URL;

//GAS - Currently using same GAS accross all environments
gasLimit = process.env.GAS_LIMIT;
gasPrice = process.env.GAS_PRICE;

module.exports = {
  // contracts_build_directory: '/build/contracts',
  networks: {
    testnet: {
      network_id: '2', // Any network (default: none)
      provider: () => {
        const truffleProvider = new TruffleProvider(
          testnet_url,
          { memonic: operator_meemonic },
          { shardID: 0, chainId: 2 },
          { gasLimit: gasLimit, gasPrice: gasPrice }
        );
        const newAcc = truffleProvider.addByPrivateKey(operator_private_key);
        truffleProvider.setSigner(newAcc);
        return truffleProvider;
      }
    },
    mainnet0: {
      network_id: '1', // Any network (default: none)
      provider: () => {
        const truffleProvider = new TruffleProvider(
          mainnet_url,
          { memonic: mainnet_mnemonic },
          { shardID: 0, chainId: 1 },
          { gasLimit: gasLimit, gasPrice: gasPrice }
        );
        const newAcc = truffleProvider.addByPrivateKey(mainnet_private_key);
        truffleProvider.setSigner(newAcc);
        return truffleProvider;
      }
    }
  },

  // Set default mocha options here, use special reporters etc.
  mocha: {
    // timeout: 100000
    useColors: true
  },

  // Configure your compilers
  compilers: {
    solc: {
      version: '0.5.8'
    }
  }
};

const express = require('express');
const router = express.Router();
const fs = require('fs');
const theatreHelpers = require('../helpers/theatreHelpers');
const passport = require('passport');
const date = require('date-and-time');
const isTheatre = require('../middleware/auth').isTheatre;

router.get('/login', (req, res) => {
  if (req.isAuthenticated() && req.user.theatre) {
    res.redirect('/theatre');
  } else {
    if (req.session.messages) {
      res.render('theatre/login', { title: 'Theatre | Login', messages: req.session.messages, theatreStyle: true });
      req.session.messages = false;
    } else {
      res.render('theatre/login', { title: 'Theatre | Login', theatreStyle: true });
    }
  }
});

router.post('/login', passport.authenticate('theatre-login', { successRedirect: '/theatre', failureRedirect: '/theatre/login', failureFlash: true }));

router.get('/auth/google', passport.authenticate('theatre-google-auth', { scope: ['profile', 'email'] }));

router.get('/auth/google/callback', passport.authenticate('theatre-google-auth', { failureRedirect: '/theatre/popup', failureFlash: true }), (req, res) => {
  res.redirect('/theatre/popup');
});

router.get('/popup', (req, res) => {
  if (!req.isAuthenticated()) {
    req.session.messages = { error: 'Invalid Account' };
  }
  res.render('auth-popup-callback');
});

router.get('/logout', (req, res) => {
  req.logout();
  res.json({ status: true });
});

router.get('/', isTheatre, async function (req, res, next) {
  const totalShows = await theatreHelpers.getNumberOfShows(req.user._id);
  const totalScreens = await theatreHelpers.getNumberOfScreens(req.user._id);
  const totalBookings = await theatreHelpers.getNumberOfBookings(req.user._id);
  const paidBookings = await theatreHelpers.getNumberOfPayedBookings(req.user._id);
  const unpaidBookings = await theatreHelpers.getNumberOfUnpayedBookings(req.user._id);
  const currentMonthBookings = await theatreHelpers.getTheatreBookings(req.user._id, date.format(new Date(), 'YYYY'), date.format(new Date(), 'MM'), date.format(new Date(), 'DD'));
  const pastMonthBookings = await theatreHelpers.getTheatreBookings(req.user._id, date.format(new Date(), 'YYYY'), date.format(new Date(new Date().getFullYear(), new Date().getMonth(), 0), 'MM'), date.format(new Date(new Date().getFullYear(), new Date().getMonth(), 0), 'DD'));
  res.render('theatre/dashboard', { title: 'Theatre | Dashboard', theatre: req.user, totalShows, totalScreens, totalBookings, paidBookings, unpaidBookings, currentMonthBookings, pastMonthBookings });
});

router.post('/update-owner-picture/:id', isTheatre, (req, res) => {
  if (req.files.ownerPicture) {
    theatreHelpers.updateOwnerPicture(req.params.id, true).then((response) => {

      let image = req.files.ownerPicture;

      image.mv(`./public/images/theatre/${response.theatre._id}.jpg`, (err, done) => {
        if (err) {
          console.log(err);
        } else {
          console.log(done);
        }
      });
      req.flash('info', response.alertMessage);
      res.redirect('/theatre');
    }).catch((error) => {
      req.flash('error', error.errMessage);
      res.redirect('/theatre');
    });
  }
});

router.get('/remove-owner-picture/:id', isTheatre, (req, res) => {
  theatreHelpers.updateOwnerPicture(req.params.id, false).then((response) => {
    req.flash('info', response.alertMessage);
    fs.unlinkSync(`./public/images/theatre/${response.theatre._id}.jpg`);
    res.redirect('/theatre');
  }).catch((error) => {
    req.flash('error', error.errMessage);
    res.redirect('/theatre');
  });;
});

